export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);

    if (url.pathname === "/") {
      return new Response(
        JSON.stringify(
          {
            service: "public-gateway",
            routes: {
              "/api/profile/:id": "forwards to svc-profile",
              "/api/geo": "forwards to svc-geo",
              "/api/echo": "forwards to svc-utils",
              "/api/aggregate/:id": "forwards to svc-aggregate (calls other services)"
            }
          },
          null,
          2
        ),
        { status: 200, headers: { "content-type": "application/json; charset=utf-8" } }
      );
    }

    if (url.pathname.startsWith("/api/profile/")) {
      const id = url.pathname.split("/").pop();
      const forwarded = new Request(`https://svc-profile/v1/profile/${encodeURIComponent(id)}`, request);
      return env.SVC_PROFILE.fetch(forwarded);
    }

    if (url.pathname === "/api/geo") {
      const forwarded = new Request(`https://svc-geo/v1/geo`, request);
      return env.SVC_GEO.fetch(forwarded);
    }

    if (url.pathname === "/api/echo") {
      const forwarded = new Request(`https://svc-utils/v1/echo`, request);
      return env.SVC_UTILS.fetch(forwarded);
    }

    if (url.pathname.startsWith("/api/aggregate/")) {
      const id = url.pathname.split("/").pop();
      const forwarded = new Request(`https://svc-aggregate/v1/aggregate/${encodeURIComponent(id)}`, request);
      return env.SVC_AGGREGATE.fetch(forwarded);
    }

    return new Response(
      JSON.stringify({ error: "not_found", path: url.pathname }, null, 2),
      { status: 404, headers: { "content-type": "application/json; charset=utf-8" } }
    );
  }
};

// =========================================
// worker: svc-profile (internal)
// =========================================
export const svcProfile = {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);

    if (url.pathname === "/v1/health") {
      return json({ ok: true, service: "svc-profile" });
    }

    if (request.method !== "GET") return json({ error: "method_not_allowed" }, 405);

    const m = url.pathname.match(/^\/v1\/profile\/([^/]+)$/);
    if (!m) return json({ error: "not_found" }, 404);

    const id = decodeURIComponent(m[1]);

    const profile = {
      id,
      displayName: `user-${id}`,
      plan: id === "1" ? "pro" : "free",
      updatedAt: new Date().toISOString()
    };

    return json(profile);
  }
};

// =========================================
// worker: svc-geo (internal)
// =========================================
export const svcGeo = {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);

    if (url.pathname === "/v1/health") {
      return json({ ok: true, service: "svc-geo" });
    }

    if (request.method !== "GET") return json({ error: "method_not_allowed" }, 405);

    if (url.pathname !== "/v1/geo") return json({ error: "not_found" }, 404);

    const cf = request.cf || {};
    return json({
      country: cf.country || null,
      region: cf.region || null,
      city: cf.city || null,
      latitude: cf.latitude || null,
      longitude: cf.longitude || null,
      colo: cf.colo || null
    });
  }
};

// =========================================
// worker: svc-utils (internal)
// =========================================
export const svcUtils = {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);

    if (url.pathname === "/v1/health") {
      return json({ ok: true, service: "svc-utils" });
    }

    if (url.pathname === "/v1/echo") {
      const headers = {};
      for (const [k, v] of request.headers.entries()) headers[k] = v;

      let body = null;
      const ct = request.headers.get("content-type") || "";
      if (request.method !== "GET" && request.method !== "HEAD") {
        if (ct.includes("application/json")) {
          try {
            body = await request.json();
          } catch {
            body = await request.text();
          }
        } else {
          body = await request.text();
        }
      }

      return json({
        method: request.method,
        url: request.url,
        headers,
        body
      });
    }

    return json({ error: "not_found" }, 404);
  }
};

// =========================================
// worker: svc-aggregate (internal; calls other internal workers)
// Accessible to any service binding.
// Requires bindings: SVC_PROFILE, SVC_GEO
// =========================================
export const svcAggregate = {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);

    if (url.pathname === "/v1/health") {
      return json({ ok: true, service: "svc-aggregate" });
    }

    if (request.method !== "GET") return json({ error: "method_not_allowed" }, 405);

    const m = url.pathname.match(/^\/v1\/aggregate\/([^/]+)$/);
    if (!m) return json({ error: "not_found" }, 404);

    const id = decodeURIComponent(m[1]);

    const [profileRes, geoRes] = await Promise.all([
      env.SVC_PROFILE.fetch(new Request(`https://svc-profile/v1/profile/${encodeURIComponent(id)}`, request)),
      env.SVC_GEO.fetch(new Request(`https://svc-geo/v1/geo`, request))
    ]);

    if (!profileRes.ok) return passthroughError(profileRes, "svc-profile");
    if (!geoRes.ok) return passthroughError(geoRes, "svc-geo");

    const [profile, geo] = await Promise.all([profileRes.json(), geoRes.json()]);

    return json({
      id,
      profile,
      geo,
      aggregatedAt: new Date().toISOString()
    });
  }
};

// =========================================
// shared helpers
// =========================================
function json(obj, status = 200, headers = {}) {
  return new Response(JSON.stringify(obj, null, 2), {
    status,
    headers: {
      "content-type": "application/json; charset=utf-8",
      ...headers
    }
  });
}

async function passthroughError(res, serviceName) {
  let payload = null;
  const ct = res.headers.get("content-type") || "";
  try {
    payload = ct.includes("application/json") ? await res.json() : await res.text();
  } catch {
    payload = null;
  }
  return json(
    {
      error: "upstream_error",
      service: serviceName,
      status: res.status,
      body: payload
    },
    502
  );
}